import { completeLinkSession, failLinkSession } from "../lib/backend-client.js";
import {
  clearPendingConfirmation,
  createPendingConfirmation,
  createSession,
  getLatestPendingSession,
  getPendingConfirmation,
  getSession,
  updateSession,
} from "../lib/session-store.js";
import { createZcaJsAdapter } from "../adapters/zca-js-adapter.js";
import type { QrLoginState, StartLinkSessionInput } from "../adapters/zalo-adapter.js";
import { env } from "../lib/env.js";

function normalizeText(text: string): string {
  return text.trim().replace(/\s+/g, " ").toLocaleLowerCase("vi-VN");
}

function extractLinkToken(text: string): string | null {
  const normalized = text.trim().replace(/\s+/g, " ");
  if (!normalized) return null;
  const prefix = (env.ZALO_LINK_MESSAGE_PREFIX || "LINK").trim();
  const prefixed = new RegExp(`^${prefix.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\s+(.+)$`, "i").exec(normalized);
  return prefixed?.[1]?.trim() || null;
}

function isConfirm(text: string): boolean {
  const normalized = normalizeText(text);
  return ["co", "có", "yes", "y", "ok", "dong y", "đồng ý", "xac nhan", "xác nhận"].includes(normalized);
}

function isCancel(text: string): boolean {
  const normalized = normalizeText(text);
  return ["huy", "hủy", "cancel", "khong", "không", "no"].includes(normalized);
}

function studentLabel(studentName: string | null | undefined, studentId: string): string {
  return studentName?.trim() || `học viên ${studentId}`;
}

function confirmationPrompt(studentName: string | null | undefined, studentId: string): string {
  return [
    `Bạn đang muốn liên kết Zalo với ${studentLabel(studentName, studentId)} đúng không?`,
    "Vui lòng trả lời CÓ để xác nhận hoặc HỦY để hủy liên kết.",
  ].join("\n");
}

function welcomeMenu(studentName: string | null | undefined, studentId: string): string {
  return [
    `Liên kết Zalo thành công với ${studentLabel(studentName, studentId)}.`,
    "Menu hỗ trợ:",
    "1. Xem tiến độ học tập",
    "2. Xem lịch học",
    "3. Liên hệ trung tâm/giáo viên",
    "Bạn có thể nhắn nội dung cần hỗ trợ ngay tại đây.",
  ].join("\n");
}

async function safeSend(adapter: ReturnType<typeof createZcaJsAdapter>, senderId: string, text: string): Promise<void> {
  try {
    await adapter.sendMessage(senderId, text);
  } catch (error) {
    // Keep the link flow resilient even if outbound Zalo send fails.
    console.error("Failed to send Zalo message", error);
  }
}

export function createZaloSessionService() {
  const adapter = createZcaJsAdapter({
    onMessageLinked: async ({ senderId, zaloDisplayName, text }) => {
      const token = extractLinkToken(text);
      if (token) {
        const pending = getSession(token);
        if (pending) {
          await completeLinkSession(pending.sessionId, { sender_id: senderId, zalo_display_name: zaloDisplayName ?? undefined });
          updateSession(pending.sessionToken, { status: "connected", senderId, zaloDisplayName: zaloDisplayName ?? null, errorMessage: null });
          clearPendingConfirmation(senderId);
          await safeSend(adapter, senderId, welcomeMenu(pending.studentName, pending.studentId));
          return;
        }
      }

      const confirmation = getPendingConfirmation(senderId);
      if (confirmation) {
        if (isConfirm(text)) {
          await completeLinkSession(confirmation.sessionId, { sender_id: senderId, zalo_display_name: zaloDisplayName ?? undefined });
          updateSession(confirmation.sessionToken, {
            status: "connected",
            senderId,
            zaloDisplayName: zaloDisplayName ?? null,
            errorMessage: null,
          });
          clearPendingConfirmation(senderId);
          await safeSend(adapter, senderId, welcomeMenu(confirmation.studentName, confirmation.studentId));
          return;
        }

        if (isCancel(text)) {
          clearPendingConfirmation(senderId);
          await safeSend(adapter, senderId, "Đã hủy liên kết. Vui lòng quay lại app và quét lại QR nếu bạn muốn liên kết Zalo.");
          return;
        }

        await safeSend(adapter, senderId, confirmationPrompt(confirmation.studentName, confirmation.studentId));
        return;
      }

      const pending = getLatestPendingSession();
      if (!pending) {
        await safeSend(adapter, senderId, "Vui lòng mở app và quét QR liên kết Zalo trước, sau đó nhắn lại tại đây.");
        return;
      }

      createPendingConfirmation(senderId, pending, text);
      await safeSend(adapter, senderId, confirmationPrompt(pending.studentName, pending.studentId));
    },
    onSessionFailed: async ({ sessionId, status, errorMessage }) => {
      await failLinkSession(sessionId, { status, error_message: errorMessage ?? null });
    },
    updateSession: async (sessionToken, patch) => {
      updateSession(sessionToken, patch);
    },
  });

  return {
    adapter,
    async restore() {
      await adapter.restore();
    },
    async loginWithQR(): Promise<QrLoginState> {
      return adapter.loginWithQR();
    },
    getLoginState(): QrLoginState {
      return adapter.getLoginState();
    },
    async startLinkSession(input: StartLinkSessionInput) {
      createSession({
        sessionId: input.sessionId,
        sessionToken: input.sessionToken,
        studentId: input.studentId,
        studentName: input.studentName ?? null,
        studentLevel: input.studentLevel ?? null,
        status: "pending",
        qrCodeUrl: null,
        deepLinkUrl: null,
        senderId: null,
        zaloDisplayName: null,
        expiresAt: input.expiresAt,
        errorMessage: null,
      });
      return adapter.startLinkSession(input);
    },
    async getSessionStatus(sessionToken: string) {
      return getSession(sessionToken);
    },
    async handleIncomingMessage(message: { senderId: string; text: string; zaloDisplayName?: string | null }) {
      return adapter.handleIncomingMessage(message);
    },
  };
}

