                        <p className={`mt-1 text-caption ${outbound ? "text-white/70" : "text-ink/45"}`}>
                          {formatDateTime(message.sent_at)}
                        </p>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </>
        )}
      </section>
    </div>
  );
}

